const item = $input.item.json;
const body = item.body_text ?? '';

const MAX_BODY_CHARS = 12000;
const bodyTrunc = body.substring(0, MAX_BODY_CHARS);
const wasTruncated = body.length > MAX_BODY_CHARS;

const sentAt = item.sent_at
  ? new Date(item.sent_at).toLocaleDateString('es-ES', { year: 'numeric', month: 'long', day: 'numeric' })
  : 'desconocida';

let prompt;

if (item.entity_type === 'email_thread') {
  // Thread analysis: determine if resolved + sentiment
  prompt = `Analiza el siguiente hilo de correo electrónico empresarial completo.
El hilo tiene ${item.message_count ?? '?'} mensajes. El estado actual es "${item.current_status || 'open'}".
La última actividad fue el ${sentAt}.

Responde EXCLUSIVAMENTE en JSON válido con esta estructura exacta, sin ningún texto adicional fuera del JSON:
{
  "summary": "resumen breve del hilo en 1-2 frases",
  "sentiment_label": "positive" | "neutral" | "negative" | "mixed",
  "sentiment_score": número entre -1.0 y 1.0,
  "resolved": true si la conversación parece resuelta/cerrada, false si sigue abierta o pendiente,
  "recommended_status": "closed" | "waiting_client" | "waiting_team" | "open",
  "complaint_flag": true o false,
  "satisfaction_flag": true o false,
  "needs_follow_up": true o false,
  "urgency_score": número entre 0.0 y 1.0,
  "topics": ["topic1", "topic2"],
  "risks": ["riesgo1", "riesgo2"],
  "action_items": [{"text": "descripción de la acción", "priority": "low|medium|high|critical"}]
}

Criterios para resolved=true:
- Últimos mensajes son agradecimientos, confirmaciones, o "OK"
- Se ha llegado a un acuerdo o se ha entregado lo solicitado
- No hay preguntas pendientes sin responder

Criterios para resolved=false:
- Hay preguntas sin responder
- Se espera una acción o entrega pendiente
- La conversación se interrumpió sin conclusión

Asunto: ${(item.subject ?? '').substring(0, 200)}
Última dirección: ${item.direction}${wasTruncated ? '\n[Contenido truncado]' : ''}

Conversación completa:\n${bodyTrunc}`;

} else {
  // Email or transcript analysis
  const tipo = item.entity_type === 'email_message' ? 'Email' : 'Transcripción de reunión';
  prompt = `Analiza el siguiente contenido de comunicación empresarial.
Responde EXCLUSIVAMENTE en JSON válido con esta estructura exacta, sin ningún texto adicional fuera del JSON:
{
  "summary": "resumen breve en 1-2 frases del contenido",
  "sentiment_label": "positive" | "neutral" | "negative" | "mixed",
  "sentiment_score": número entre -1.0 y 1.0,
  "complaint_flag": true o false,
  "satisfaction_flag": true o false,
  "needs_follow_up": true o false,
  "urgency_score": número entre 0.0 y 1.0,
  "topics": ["topic1", "topic2"],
  "risks": ["riesgo1", "riesgo2"],
  "action_items": [{"text": "descripción de la acción", "priority": "low|medium|high|critical"}]
}

Tipo: ${tipo}
Asunto: ${(item.subject ?? '').substring(0, 200)}
Dirección: ${item.direction}
Fecha: ${sentAt}${wasTruncated ? '\n[Contenido truncado a los primeros 12.000 caracteres]' : ''}

Contenido:\n${bodyTrunc}`;
}

return [{
  json: {
    ...item,
    prompt,
    body_truncated: wasTruncated
  }
}];

const ctx      = $('Build prompt').item.json;
const aiOutput = $input.item.json;

const rawText = aiOutput?.output?.[0]?.content?.[0]?.text
  ?? aiOutput?.message?.content
  ?? aiOutput?.choices?.[0]?.message?.content
  ?? '';

let parsed;
try {
  const jsonMatch = rawText.match(/\{[\s\S]*\}/);
  if (!jsonMatch) throw new Error('No JSON block found');
  parsed = JSON.parse(jsonMatch[0]);
} catch (err) {
  console.error(`[AI] JSON parse failed for ${ctx.entity_id}: ${err.message}`);
  return [];
}

const VALID_SENTIMENTS = ['positive', 'neutral', 'negative', 'mixed'];
const VALID_PRIORITIES = ['low', 'medium', 'high', 'critical'];
const VALID_STATUSES = ['closed', 'waiting_client', 'waiting_team', 'open'];

const validated = {
  summary:           typeof parsed.summary === 'string' ? parsed.summary.substring(0, 1000) : '',
  sentiment_label:   VALID_SENTIMENTS.includes(parsed.sentiment_label) ? parsed.sentiment_label : 'neutral',
  sentiment_score:   typeof parsed.sentiment_score === 'number' ? Math.max(-1, Math.min(1, parsed.sentiment_score)) : 0,
  complaint_flag:    parsed.complaint_flag === true,
  satisfaction_flag:  parsed.satisfaction_flag === true,
  needs_follow_up:   parsed.needs_follow_up === true,
  urgency_score:     typeof parsed.urgency_score === 'number' ? Math.max(0, Math.min(1, parsed.urgency_score)) : 0,
  topics:            Array.isArray(parsed.topics) ? parsed.topics.filter(t => typeof t === 'string').slice(0, 20) : [],
  risks:             Array.isArray(parsed.risks) ? parsed.risks.filter(r => typeof r === 'string').slice(0, 20) : [],
  action_items:      Array.isArray(parsed.action_items)
    ? parsed.action_items.filter(a => a?.text).map(a => ({ text: String(a.text).substring(0, 500), priority: VALID_PRIORITIES.includes(a.priority) ? a.priority : 'medium' })).slice(0, 20)
    : []
};

// Thread-specific fields
const threadFields = ctx.entity_type === 'email_thread' ? {
  resolved: parsed.resolved === true,
  recommended_status: VALID_STATUSES.includes(parsed.recommended_status) ? parsed.recommended_status : null
} : {};

return [{
  json: {
    entity_id:   ctx.entity_id,
    entity_type: ctx.entity_type,
    client_id:   ctx.client_id,
    subject:     ctx.subject,
    ...validated,
    ...threadFields,
    raw_output: parsed,
    is_high_risk: validated.complaint_flag || validated.urgency_score >= 0.8
  }
}];

const insight    = $('Validate + parse response').item.json;
const insightRow = $input.item.json;

if (!insight.action_items?.length) return [];

return insight.action_items.map(a => ({
  json: {
    insight_id: insightRow.insight_id,
    client_id:  insight.client_id,
    text:       a.text,
    priority:   a.priority
  }
}));

// Only process thread entities — skip emails and transcripts
const insight = $('Validate + parse response').item.json;
if (insight.entity_type !== 'email_thread') return [];
if (!insight.recommended_status) return [];

return [{
  json: {
    thread_id: insight.entity_id,
    new_status: insight.recommended_status
  }
}];

parameters.query:
UPDATE email_threads
SET status = '{{ $json.new_status }}'::public.thread_status
WHERE id = '{{ $json.thread_id }}';
